-- Aplicar Plantilla HTML exacta proporcionada por el usuario
-- Se usa prefijo N' para asegurar codificación Unicode

BEGIN TRANSACTION;

DECLARE @HTML_TEMPLATE NVARCHAR(MAX) = N'<!DOCTYPE html><html><head><meta charset="UTF-8"><style type="text/css">body{margin:0;padding:0;background-color:#f0f8ff!important;font-family:''Segoe UI'',Tahoma,Geneva,Verdana,sans-serif}table{border-spacing:0;border-collapse:collapse}td{padding:0}</style></head><body style="margin:0;padding:0;background-color:#f0f8ff;"><table role="presentation" width="100%" border="0" cellspacing="0" cellpadding="0" style="background-color:#f0f8ff;width:100%;"><tr><td align="center" style="padding:40px 0;"><table role="presentation" width="600" border="0" cellspacing="0" cellpadding="0" style="background-color:#ffffff;max-width:600px;width:100%;border-radius:12px;overflow:hidden;box-shadow:0 10px 25px rgba(0,98,168,0.15);border:1px solid #dbeafe;"><thead><tr><td style="background-color:#ffffff;padding:20px 40px;border-bottom:6px solid #0062a8;"><img src="{LOGO_URL}" alt="ADL ONE" width="240" style="display:block;width:240px;max-width:240px;height:auto;border:0;"></td></tr></thead><tbody><tr><td style="padding:40px;"><h2 style="margin:0 0 5px 0;color:#0062a8;font-family:Arial,sans-serif;font-size:22px;font-weight:700;">{TITULO_CORREO}</h2><p style="margin:0 0 25px 0;color:#5c8ab9;font-family:Arial,sans-serif;font-size:18px;">Solicitud Nº: <strong style="color:#ff8c00;font-size:24px;">{CORRELATIVO}</strong></p> <div style="margin-top:20px; border-top: 1px solid #e6f2ff; padding-top: 20px;">     {EQUIPOS_DETALLE} </div> {BLOQUE_OBSERVACION|{ETIQUETA_OBSERVACION}} <table width="100%" border="0" cellspacing="0" cellpadding="0" style="margin-top:20px;border-top:1px solid #e6f2ff;padding-top:20px;"><tr><td style="padding:4px 0;color:#0062a8;font-weight:bold;font-size:14px;font-family:Arial,sans-serif;">Solicitado por: <span style="color:#333333;font-weight:normal;">{SOLICITANTE}</span></td></tr><tr><td style="padding:4px 0;color:#0062a8;font-weight:bold;font-size:14px;font-family:Arial,sans-serif;">Fecha de solicitud: <span style="color:#333333;font-weight:normal;">{FECHA}</span></td></tr><tr><td style="padding:4px 0;color:#0062a8;font-weight:bold;font-size:14px;font-family:Arial,sans-serif;">Hora de solicitud: <span style="color:#333333;font-weight:normal;">{HORA}</span></td></tr></table></td></tr><tr><td style="padding:25px 40px;background-color:#f8fafc;border-top:1px solid #dbeafe;"><table width="100%" border="0" cellspacing="0" cellpadding="0"><tr><td align="left" valign="top" style="padding-right:20px;"><strong style="color:#0062a8;font-size:13px;font-family:Arial,sans-serif;display:block;margin-bottom:4px;">ADL Diagnostic Chile SpA</strong><div style="color:#64748b;font-size:11px;line-height:1.4;font-family:Arial,sans-serif;">Laboratorio de Diagnóstico y Biotecnología<br>Sector La Vara s/n Camino a Alerce, Puerto Montt<br>Tel/fax: (56 65) 2250292 - 2250234 – 2250287<br><a href="http://www.adldiagnostic.cl" style="color:#0062a8;text-decoration:none;">www.adldiagnostic.cl</a></div></td><td align="right" valign="top" style="color:#94a3b8;font-size:11px;font-family:Arial,sans-serif;white-space:nowrap;">Sistema de Gestión<br><strong style="color:#0062a8;">Empresarial</strong></td></tr></table></td></tr></tbody></table></td></tr></table></body></html>';

UPDATE mae_evento_notificacion
SET cuerpo_template_html = @HTML_TEMPLATE
WHERE codigo_evento IN (N'SOLICITUD_NUEVA', N'SOLICITUD_ESTADO_CAMBIO', N'SOLICITUD_COMENTARIO_NUEVO', N'SOLICITUD_DERIVACION');

COMMIT TRANSACTION;
PRINT 'Plantillas de email restauradas al formato exacto solicitado.';
